INSERT INTO `exercice` (`exercice_id`, `source_id`, `external_id`, `nom`, `gif_180_path`, `gif_360_path`, `gif_720_path`, `gif_1080_path`, `body_part_principale`, `muscle_cible_principal`, `equipement_principal`, `body_parts_json`, `target_muscles_json`, `secondary_muscles_json`, `equipments_json`, `instructions_json`, `cree_le`) VALUES
(1, 4, '2ORFMoR', 'hack calf raise', 'gifs_180x180/2ORFMoR.gif', 'gifs_360x360/2ORFMoR.gif', 'gifs_720x720/2ORFMoR.gif', 'gifs_1080x1080/2ORFMoR.gif', 'lower legs', 'calves', 'sled machine', '[\"lower legs\"]', '[\"calves\"]', '[\"hamstrings\", \"glutes\"]', '[\"sled machine\"]', '[\"Step:1 Adjust the sled machine to a comfortable weight.\", \"Step:2 Stand on the sled machine with your toes on the platform and your heels hanging off.\", \"Step:3 Hold onto the handles for stability.\", \"Step:4 Raise your heels as high as possible by pushing through the balls of your feet.\", \"Step:5 Pause for a moment at the top, then slowly lower your heels back down to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(2, 4, '2Qh2J1e', 'sled 45° leg press (side pov)', 'gifs_180x180/2Qh2J1e.gif', 'gifs_360x360/2Qh2J1e.gif', 'gifs_720x720/2Qh2J1e.gif', 'gifs_1080x1080/2Qh2J1e.gif', 'upper legs', 'glutes', 'sled machine', '[\"upper legs\"]', '[\"glutes\"]', '[\"quadriceps\", \"hamstrings\", \"calves\"]', '[\"sled machine\"]', '[\"Step:1 Adjust the seat of the sled machine so that your knees are at a 90-degree angle when your feet are on the footplate.\", \"Step:2 Sit on the sled machine with your back flat against the backrest and your feet shoulder-width apart on the footplate.\", \"Step:3 Grip the handles on the sides of the seat for stability.\", \"Step:4 Push against the footplate to extend your legs, straightening them completely.\", \"Step:5 Pause for a moment at the top, then slowly bend your knees to lower the footplate back to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(3, 4, '3eGE2JC', 'dumbbell front raise', 'gifs_180x180/3eGE2JC.gif', 'gifs_360x360/3eGE2JC.gif', 'gifs_720x720/3eGE2JC.gif', 'gifs_1080x1080/3eGE2JC.gif', 'shoulders', 'delts', 'dumbbell', '[\"shoulders\"]', '[\"delts\"]', '[\"biceps\", \"trapezius\"]', '[\"dumbbell\"]', '[\"Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.\", \"Step:2 Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.\", \"Step:3 Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.\", \"Step:4 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(4, 4, '3tAXPQ6', 'dumbbell over bench revers wrist curl', 'gifs_180x180/3tAXPQ6.gif', 'gifs_360x360/3tAXPQ6.gif', 'gifs_720x720/3tAXPQ6.gif', 'gifs_1080x1080/3tAXPQ6.gif', 'lower arms', 'forearms', 'dumbbell', '[\"lower arms\"]', '[\"forearms\"]', '[\"biceps\", \"brachialis\"]', '[\"dumbbell\"]', '[\"Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing down.\", \"Step:2 Rest your forearms on the bench, allowing your wrists to hang off the edge.\", \"Step:3 Slowly curl your wrists upward, bringing the dumbbells towards your body.\", \"Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.\", \"Step:5 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(5, 4, '3TZduzM', 'barbell incline bench press', 'gifs_180x180/3TZduzM.gif', 'gifs_360x360/3TZduzM.gif', 'gifs_720x720/3TZduzM.gif', 'gifs_1080x1080/3TZduzM.gif', 'chest', 'pectorals', 'barbell', '[\"chest\"]', '[\"pectorals\"]', '[\"shoulders\", \"triceps\"]', '[\"barbell\"]', '[\"Step:1 Set up an incline bench at a 45-degree angle.\", \"Step:2 Lie down on the bench with your feet flat on the ground.\", \"Step:3 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.\", \"Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle.\", \"Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(6, 4, '3XFdb1Z', 'cable squatting curl', 'gifs_180x180/3XFdb1Z.gif', 'gifs_360x360/3XFdb1Z.gif', 'gifs_720x720/3XFdb1Z.gif', 'gifs_1080x1080/3XFdb1Z.gif', 'upper arms', 'biceps', 'cable', '[\"upper arms\"]', '[\"biceps\"]', '[\"forearms\"]', '[\"cable\"]', '[\"Step:1 Attach a cable handle to the lowest setting on a cable machine.\", \"Step:2 Stand facing the machine with your feet shoulder-width apart.\", \"Step:3 Hold the cable handle with an underhand grip, palms facing up, and arms fully extended.\", \"Step:4 Lower your body into a squat position, keeping your back straight and knees behind your toes.\", \"Step:5 As you squat down, curl the cable handle towards your shoulders, keeping your elbows close to your sides.\", \"Step:6 Pause for a moment at the top of the curl, squeezing your biceps.\", \"Step:7 Slowly lower the cable handle back to the starting position, fully extending your arms.\", \"Step:8 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(7, 4, '4dF3maG', 'dumbbell one arm hammer preacher curl', 'gifs_180x180/4dF3maG.gif', 'gifs_360x360/4dF3maG.gif', 'gifs_720x720/4dF3maG.gif', 'gifs_1080x1080/4dF3maG.gif', 'upper arms', 'biceps', 'dumbbell', '[\"upper arms\"]', '[\"biceps\"]', '[\"forearms\"]', '[\"dumbbell\"]', '[\"Step:1 Sit on a preacher bench with a dumbbell in one hand and your upper arm resting on the pad.\", \"Step:2 Hold the dumbbell with a neutral grip (palms facing your body).\", \"Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.\", \"Step:4 Pause for a moment at the top, squeezing your biceps.\", \"Step:5 Inhale and slowly lower the dumbbell back to the starting position.\", \"Step:6 Repeat for the desired number of repetitions, then switch arms.\"]', '2026-04-24 17:27:47'),
(8, 4, '4dUn2iv', 'barbell standing close grip curl', 'gifs_180x180/4dUn2iv.gif', 'gifs_360x360/4dUn2iv.gif', 'gifs_720x720/4dUn2iv.gif', 'gifs_1080x1080/4dUn2iv.gif', 'upper arms', 'biceps', 'barbell', '[\"upper arms\"]', '[\"biceps\"]', '[\"forearms\"]', '[\"barbell\"]', '[\"Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, hands close together.\", \"Step:2 Keep your elbows close to your torso and your upper arms stationary throughout the movement.\", \"Step:3 Exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.\", \"Step:4 Hold the contracted position for a brief pause as you squeeze your biceps.\", \"Step:5 Inhale as you slowly begin to bring the barbell back to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(9, 4, '5bpPTHv', 'kettlebell pistol squat', 'gifs_180x180/5bpPTHv.gif', 'gifs_360x360/5bpPTHv.gif', 'gifs_720x720/5bpPTHv.gif', 'gifs_1080x1080/5bpPTHv.gif', 'upper legs', 'glutes', 'kettlebell', '[\"upper legs\"]', '[\"glutes\"]', '[\"quadriceps\", \"hamstrings\", \"calves\"]', '[\"kettlebell\"]', '[\"Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands.\", \"Step:2 Lift your left foot off the ground and extend it forward, keeping it parallel to the ground.\", \"Step:3 Slowly lower your body down into a squat position, keeping your right foot flat on the ground and your left leg extended.\", \"Step:4 Pause for a moment at the bottom of the squat, then push through your right heel to return to the starting position.\", \"Step:5 Repeat for the desired number of repetitions, then switch legs.\"]', '2026-04-24 17:27:47'),
(10, 4, '05Cf2v8', 'impossible dips', 'gifs_180x180/05Cf2v8.gif', 'gifs_360x360/05Cf2v8.gif', 'gifs_720x720/05Cf2v8.gif', 'gifs_1080x1080/05Cf2v8.gif', 'upper arms', 'triceps', 'body weight', '[\"upper arms\"]', '[\"triceps\"]', '[\"chest\", \"shoulders\"]', '[\"body weight\"]', '[\"Step:1 Position yourself between two parallel bars with your arms fully extended and your body suspended in the air.\", \"Step:2 Bend your knees and cross your ankles.\", \"Step:3 Lower your body by bending your elbows until your upper arms are parallel to the ground.\", \"Step:4 Pause for a moment, then push yourself back up to the starting position by straightening your arms.\", \"Step:5 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(11, 4, '5uFK1xr', 'barbell seated overhead triceps extension', 'gifs_180x180/5uFK1xr.gif', 'gifs_360x360/5uFK1xr.gif', 'gifs_720x720/5uFK1xr.gif', 'gifs_1080x1080/5uFK1xr.gif', 'upper arms', 'triceps', 'barbell', '[\"upper arms\"]', '[\"triceps\"]', '[\"shoulders\"]', '[\"barbell\"]', '[\"Step:1 Sit on a bench with your back straight and feet flat on the ground.\", \"Step:2 Hold a barbell with an overhand grip, hands shoulder-width apart, and raise it overhead.\", \"Step:3 Lower the barbell behind your head by bending your elbows, keeping your upper arms close to your head.\", \"Step:4 Pause for a moment, then extend your arms to raise the barbell back to the starting position.\", \"Step:5 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(12, 4, '5v7KYld', 'smith incline bench press', 'gifs_180x180/5v7KYld.gif', 'gifs_360x360/5v7KYld.gif', 'gifs_720x720/5v7KYld.gif', 'gifs_1080x1080/5v7KYld.gif', 'chest', 'pectorals', 'smith machine', '[\"chest\"]', '[\"pectorals\"]', '[\"shoulders\", \"triceps\"]', '[\"smith machine\"]', '[\"Step:1 Adjust the bench to a 30-45 degree incline.\", \"Step:2 Sit on the bench with your back flat against the pad and feet firmly on the ground.\", \"Step:3 Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.\", \"Step:4 Unrack the barbell and lower it slowly towards your upper chest, keeping your elbows slightly tucked in.\", \"Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position, fully extending your arms.\", \"Step:6 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(13, 4, '6bOA1Oi', 'weighted side bend (on stability ball)', 'gifs_180x180/6bOA1Oi.gif', 'gifs_360x360/6bOA1Oi.gif', 'gifs_720x720/6bOA1Oi.gif', 'gifs_1080x1080/6bOA1Oi.gif', 'waist', 'abs', 'weighted', '[\"waist\"]', '[\"abs\"]', '[\"obliques\", \"lower back\"]', '[\"weighted\"]', '[\"Step:1 Sit on a stability ball with your feet shoulder-width apart and flat on the ground.\", \"Step:2 Hold a weight in one hand and place your other hand on your hip.\", \"Step:3 Engage your core and slowly bend sideways towards the weighted side, keeping your back straight.\", \"Step:4 Pause for a moment at the bottom, then slowly return to the starting position.\", \"Step:5 Repeat for the desired number of repetitions, then switch sides.\"]', '2026-04-24 17:27:47'),
(14, 4, '6cKQC5E', 'dumbbell one arm upright row', 'gifs_180x180/6cKQC5E.gif', 'gifs_360x360/6cKQC5E.gif', 'gifs_720x720/6cKQC5E.gif', 'gifs_1080x1080/6cKQC5E.gif', 'shoulders', 'delts', 'dumbbell', '[\"shoulders\"]', '[\"delts\"]', '[\"traps\", \"biceps\"]', '[\"dumbbell\"]', '[\"Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip.\", \"Step:2 Let the dumbbell hang at arm\'s length in front of your thighs, with your palm facing your body.\", \"Step:3 Keeping your back straight and your core engaged, exhale and lift the dumbbell straight up towards your chin, leading with your elbow.\", \"Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position.\", \"Step:5 Repeat for the desired number of repetitions, then switch to the other arm.\"]', '2026-04-24 17:27:47'),
(15, 4, '6HiHHe0', 'barbell standing rocking leg calf raise', 'gifs_180x180/6HiHHe0.gif', 'gifs_360x360/6HiHHe0.gif', 'gifs_720x720/6HiHHe0.gif', 'gifs_1080x1080/6HiHHe0.gif', 'lower legs', 'calves', 'barbell', '[\"lower legs\"]', '[\"calves\"]', '[\"hamstrings\", \"quadriceps\"]', '[\"barbell\"]', '[\"Step:1 Stand with your feet shoulder-width apart and hold a barbell across your upper back.\", \"Step:2 Raise your heels off the ground as high as possible, balancing on the balls of your feet.\", \"Step:3 Slowly lower your heels back down to the starting position.\", \"Step:4 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(16, 4, '6kSxYnw', 'barbell wrist curl v. 2', 'gifs_180x180/6kSxYnw.gif', 'gifs_360x360/6kSxYnw.gif', 'gifs_720x720/6kSxYnw.gif', 'gifs_1080x1080/6kSxYnw.gif', 'lower arms', 'forearms', 'barbell', '[\"lower arms\"]', '[\"forearms\"]', '[\"biceps\", \"brachialis\"]', '[\"barbell\"]', '[\"Step:1 Sit on a bench with your feet flat on the ground and your knees bent.\", \"Step:2 Hold a barbell with an underhand grip, palms facing up, and your hands shoulder-width apart.\", \"Step:3 Rest your forearms on your thighs, allowing your wrists to hang off the edge.\", \"Step:4 Slowly curl your wrists upward, bringing the barbell towards your forearms.\", \"Step:5 Pause for a moment at the top, then slowly lower the barbell back down to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(17, 4, '6MfS53i', 'dumbbell lying single extension', 'gifs_180x180/6MfS53i.gif', 'gifs_360x360/6MfS53i.gif', 'gifs_720x720/6MfS53i.gif', 'gifs_1080x1080/6MfS53i.gif', 'upper arms', 'triceps', 'dumbbell', '[\"upper arms\"]', '[\"triceps\"]', '[\"shoulders\"]', '[\"dumbbell\"]', '[\"Step:1 Lie flat on a bench with a dumbbell in one hand and your arm fully extended above your chest.\", \"Step:2 Lower the dumbbell in a controlled manner towards your forehead, keeping your upper arm stationary.\", \"Step:3 Pause briefly at the bottom of the movement, then extend your arm back to the starting position.\", \"Step:4 Repeat for the desired number of repetitions, then switch arms.\"]', '2026-04-24 17:27:47'),
(18, 4, '6sMAmNv', 'dumbbell reverse spider curl', 'gifs_180x180/6sMAmNv.gif', 'gifs_360x360/6sMAmNv.gif', 'gifs_720x720/6sMAmNv.gif', 'gifs_1080x1080/6sMAmNv.gif', 'upper arms', 'biceps', 'dumbbell', '[\"upper arms\"]', '[\"biceps\"]', '[\"forearms\"]', '[\"dumbbell\"]', '[\"Step:1 Stand up straight with a dumbbell in each hand, palms facing your body and arms fully extended.\", \"Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.\", \"Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.\", \"Step:4 Hold the contracted position for a brief pause as you squeeze your biceps.\", \"Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(19, 4, '6sYyrRX', 'bent knee lying twist (male)', 'gifs_180x180/6sYyrRX.gif', 'gifs_360x360/6sYyrRX.gif', 'gifs_720x720/6sYyrRX.gif', 'gifs_1080x1080/6sYyrRX.gif', 'upper legs', 'glutes', 'body weight', '[\"upper legs\"]', '[\"glutes\"]', '[\"obliques\", \"hip flexors\"]', '[\"body weight\"]', '[\"Step:1 Lie flat on your back with your knees bent and feet flat on the ground.\", \"Step:2 Extend your arms out to the sides, perpendicular to your body.\", \"Step:3 Keeping your knees together, slowly lower them to one side, aiming to touch the ground with your knees.\", \"Step:4 Pause for a moment, then engage your core and slowly lift your knees back to the starting position.\", \"Step:5 Repeat the movement to the other side.\", \"Step:6 Continue alternating sides for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(20, 4, '7F1DVzn', 'lever front pulldown', 'gifs_180x180/7F1DVzn.gif', 'gifs_360x360/7F1DVzn.gif', 'gifs_720x720/7F1DVzn.gif', 'gifs_1080x1080/7F1DVzn.gif', 'back', 'lats', 'leverage machine', '[\"back\"]', '[\"lats\"]', '[\"biceps\", \"rhomboids\", \"rear deltoids\"]', '[\"leverage machine\"]', '[\"Step:1 Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.\", \"Step:2 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.\", \"Step:3 Sit upright with your chest lifted and your shoulders back, maintaining a slight arch in your lower back.\", \"Step:4 Engage your lats and pull the handles down towards your chest, squeezing your shoulder blades together.\", \"Step:5 Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(21, 4, '7I6LNUG', 'lever seated row', 'gifs_180x180/7I6LNUG.gif', 'gifs_360x360/7I6LNUG.gif', 'gifs_720x720/7I6LNUG.gif', 'gifs_1080x1080/7I6LNUG.gif', 'back', 'upper back', 'leverage machine', '[\"back\"]', '[\"upper back\"]', '[\"biceps\", \"forearms\"]', '[\"leverage machine\"]', '[\"Step:1 Adjust the seat height and footrests to a comfortable position.\", \"Step:2 Sit on the machine with your chest against the pad and your feet on the footrests.\", \"Step:3 Grasp the handles with an overhand grip, shoulder-width apart.\", \"Step:4 Keep your back straight and your core engaged.\", \"Step:5 Pull the handles towards your body, squeezing your shoulder blades together.\", \"Step:6 Pause for a moment at the peak of the movement.\", \"Step:7 Slowly release the handles and return to the starting position.\", \"Step:8 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(22, 4, '7inpWch', 'dumbbell standing concentration curl', 'gifs_180x180/7inpWch.gif', 'gifs_360x360/7inpWch.gif', 'gifs_720x720/7inpWch.gif', 'gifs_1080x1080/7inpWch.gif', 'upper arms', 'biceps', 'dumbbell', '[\"upper arms\"]', '[\"biceps\"]', '[\"forearms\"]', '[\"dumbbell\"]', '[\"Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your arm fully extended and palm facing inwards.\", \"Step:2 Place your opposite hand on your thigh for support.\", \"Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.\", \"Step:4 Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.\", \"Step:5 Hold the contracted position for a brief pause as you squeeze your biceps.\", \"Step:6 Inhale and slowly lower the dumbbell back to the starting position.\", \"Step:7 Repeat for the desired number of repetitions, then switch arms.\"]', '2026-04-24 17:27:47'),
(23, 4, '7saC5zz', 'cable decline fly', 'gifs_180x180/7saC5zz.gif', 'gifs_360x360/7saC5zz.gif', 'gifs_720x720/7saC5zz.gif', 'gifs_1080x1080/7saC5zz.gif', 'chest', 'pectorals', 'cable', '[\"chest\"]', '[\"pectorals\"]', '[\"shoulders\", \"triceps\"]', '[\"cable\"]', '[\"Step:1 Adjust the cable machine to a decline position.\", \"Step:2 Stand facing away from the machine with your feet shoulder-width apart.\", \"Step:3 Hold the handles with your palms facing forward and your arms extended straight out in front of you.\", \"Step:4 Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.\", \"Step:5 Pause for a moment at the fully extended position, then slowly return to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(24, 4, '7zdxRTl', 'smith leg press', 'gifs_180x180/7zdxRTl.gif', 'gifs_360x360/7zdxRTl.gif', 'gifs_720x720/7zdxRTl.gif', 'gifs_1080x1080/7zdxRTl.gif', 'upper legs', 'glutes', 'smith machine', '[\"upper legs\"]', '[\"glutes\"]', '[\"quadriceps\", \"hamstrings\", \"calves\"]', '[\"smith machine\"]', '[\"Step:1 Adjust the seat and footplate of the smith machine to a comfortable position.\", \"Step:2 Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate.\", \"Step:3 Grasp the handles or sides of the machine for stability.\", \"Step:4 Push the footplate away from you by extending your legs, keeping your back against the backrest.\", \"Step:5 Pause for a moment at the fully extended position.\", \"Step:6 Slowly bend your knees and lower the footplate back towards you, returning to the starting position.\", \"Step:7 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(25, 4, '8eqjhOl', 'dumbbell palms in incline bench press', 'gifs_180x180/8eqjhOl.gif', 'gifs_360x360/8eqjhOl.gif', 'gifs_720x720/8eqjhOl.gif', 'gifs_1080x1080/8eqjhOl.gif', 'upper arms', 'triceps', 'dumbbell', '[\"upper arms\"]', '[\"triceps\"]', '[\"chest\", \"shoulders\"]', '[\"dumbbell\"]', '[\"Step:1 Set up an incline bench at a 45-degree angle.\", \"Step:2 Sit on the bench with your back against the backrest and feet flat on the ground.\", \"Step:3 Hold a dumbbell in each hand with an overhand grip, palms facing inwards.\", \"Step:4 Extend your arms straight up above your chest, keeping a slight bend in your elbows.\", \"Step:5 Lower the dumbbells slowly towards your shoulders, keeping your elbows close to your body.\", \"Step:6 Pause for a moment at the bottom, then press the dumbbells back up to the starting position.\", \"Step:7 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(26, 4, '8K0w2yA', 'assisted hanging knee raise with throw down', 'gifs_180x180/8K0w2yA.gif', 'gifs_360x360/8K0w2yA.gif', 'gifs_720x720/8K0w2yA.gif', 'gifs_1080x1080/8K0w2yA.gif', 'waist', 'abs', 'assisted', '[\"waist\"]', '[\"abs\"]', '[\"hip flexors\", \"lower back\"]', '[\"assisted\"]', '[\"Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you.\", \"Step:2 Engage your core and lift your knees towards your chest, keeping your legs together.\", \"Step:3 Once your knees are at chest level, explosively throw your legs down towards the ground, extending them fully.\", \"Step:4 Allow your legs to swing back up and repeat the movement for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(27, 4, '8oYqOt9', 'cable seated curl', 'gifs_180x180/8oYqOt9.gif', 'gifs_360x360/8oYqOt9.gif', 'gifs_720x720/8oYqOt9.gif', 'gifs_1080x1080/8oYqOt9.gif', 'upper arms', 'biceps', 'cable', '[\"upper arms\"]', '[\"biceps\"]', '[\"forearms\"]', '[\"cable\"]', '[\"Step:1 Sit on a cable machine with your feet flat on the ground and your back straight.\", \"Step:2 Grasp the cable attachment with an underhand grip, palms facing up, and your arms fully extended.\", \"Step:3 Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders, contracting your biceps.\", \"Step:4 Pause for a moment at the top of the movement, squeezing your biceps.\", \"Step:5 Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.\", \"Step:6 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(28, 4, '8ozhUIZ', 'barbell standing calf raise', 'gifs_180x180/8ozhUIZ.gif', 'gifs_360x360/8ozhUIZ.gif', 'gifs_720x720/8ozhUIZ.gif', 'gifs_1080x1080/8ozhUIZ.gif', 'lower legs', 'calves', 'barbell', '[\"lower legs\"]', '[\"calves\"]', '[\"hamstrings\", \"glutes\"]', '[\"barbell\"]', '[\"Step:1 Stand with your feet shoulder-width apart and place a barbell across your upper back.\", \"Step:2 Raise your heels off the ground as high as possible, using only your toes.\", \"Step:3 Pause for a moment at the top, then slowly lower your heels back down to the starting position.\", \"Step:4 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(29, 4, '8urJS9b', 'weighted hyperextension (on stability ball)', 'gifs_180x180/8urJS9b.gif', 'gifs_360x360/8urJS9b.gif', 'gifs_720x720/8urJS9b.gif', 'gifs_1080x1080/8urJS9b.gif', 'back', 'spine', 'weighted', '[\"back\"]', '[\"spine\"]', '[\"glutes\", \"hamstrings\"]', '[\"weighted\"]', '[\"Step:1 Position yourself face down on a stability ball with your hips resting on the ball and your feet against a wall for stability.\", \"Step:2 Place your hands behind your head or cross them over your chest.\", \"Step:3 Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line.\", \"Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position.\", \"Step:5 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47'),
(30, 4, '8xUv4J7', 'cable seated crunch', 'gifs_180x180/8xUv4J7.gif', 'gifs_360x360/8xUv4J7.gif', 'gifs_720x720/8xUv4J7.gif', 'gifs_1080x1080/8xUv4J7.gif', 'waist', 'abs', 'cable', '[\"waist\"]', '[\"abs\"]', '[\"obliques\"]', '[\"cable\"]', '[\"Step:1 Sit on a cable machine with your feet flat on the ground and your knees bent.\", \"Step:2 Hold the cable handle with both hands and position it behind your head.\", \"Step:3 Engage your abs and slowly curl your upper body forward, bringing your chest towards your knees.\", \"Step:4 Pause for a moment at the top, then slowly return to the starting position.\", \"Step:5 Repeat for the desired number of repetitions.\"]', '2026-04-24 17:27:47');
