INSERT INTO `stg_import` (`stg_id`, `lot_id`, `entite`, `ref_externe`, `source_payload_json`, `payload_normalise_json`, `est_parseable`, `statut_validation`, `code_rejet_potentiel`, `cree_le`) VALUES
(1, 2, 'exercise', '2ORFMoR', '{\"exerciseId\": \"2ORFMoR\", \"name\": \"hack calf raise\", \"gifUrl\": \"2ORFMoR.gif\", \"targetMuscles\": [\"calves\"], \"bodyParts\": [\"lower legs\"], \"equipments\": [\"sled machine\"], \"secondaryMuscles\": [\"hamstrings\", \"glutes\"], \"instructions\": [\"Step:1 Adjust the sled machine to a comfortable weight.\", \"Step:2 Stand on the sled machine with your toes on the platform and your heels hanging off.\", \"Step:3 Hold onto the handles for stability.\", \"Step:4 Raise your heels as high as possible by pushing through the balls of your feet.\", \"Step:5 Pause for a moment at the top, then slowly lower your heels back down to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"2ORFMoR\", \"nom\": \"hack calf raise\", \"gif_180_path\": \"gifs_180x180/2ORFMoR.gif\", \"gif_360_path\": \"gifs_360x360/2ORFMoR.gif\", \"gif_720_path\": \"gifs_720x720/2ORFMoR.gif\", \"gif_1080_path\": \"gifs_1080x1080/2ORFMoR.gif\", \"body_part_principale\": \"lower legs\", \"muscle_cible_principal\": \"calves\", \"equipement_principal\": \"sled machine\", \"body_parts_json\": \"[\\\"lower legs\\\"]\", \"target_muscles_json\": \"[\\\"calves\\\"]\", \"secondary_muscles_json\": \"[\\\"hamstrings\\\", \\\"glutes\\\"]\", \"equipments_json\": \"[\\\"sled machine\\\"]\", \"instructions_json\": \"[\\\"Step:1 Adjust the sled machine to a comfortable weight.\\\", \\\"Step:2 Stand on the sled machine with your toes on the platform and your heels hanging off.\\\", \\\"Step:3 Hold onto the handles for stability.\\\", \\\"Step:4 Raise your heels as high as possible by pushing through the balls of your feet.\\\", \\\"Step:5 Pause for a moment at the top, then slowly lower your heels back down to the starting position.\\\", \\\"Step:6 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(2, 2, 'exercise', '2Qh2J1e', '{\"exerciseId\": \"2Qh2J1e\", \"name\": \"sled 45° leg press (side pov)\", \"gifUrl\": \"2Qh2J1e.gif\", \"targetMuscles\": [\"glutes\"], \"bodyParts\": [\"upper legs\"], \"equipments\": [\"sled machine\"], \"secondaryMuscles\": [\"quadriceps\", \"hamstrings\", \"calves\"], \"instructions\": [\"Step:1 Adjust the seat of the sled machine so that your knees are at a 90-degree angle when your feet are on the footplate.\", \"Step:2 Sit on the sled machine with your back flat against the backrest and your feet shoulder-width apart on the footplate.\", \"Step:3 Grip the handles on the sides of the seat for stability.\", \"Step:4 Push against the footplate to extend your legs, straightening them completely.\", \"Step:5 Pause for a moment at the top, then slowly bend your knees to lower the footplate back to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"2Qh2J1e\", \"nom\": \"sled 45° leg press (side pov)\", \"gif_180_path\": \"gifs_180x180/2Qh2J1e.gif\", \"gif_360_path\": \"gifs_360x360/2Qh2J1e.gif\", \"gif_720_path\": \"gifs_720x720/2Qh2J1e.gif\", \"gif_1080_path\": \"gifs_1080x1080/2Qh2J1e.gif\", \"body_part_principale\": \"upper legs\", \"muscle_cible_principal\": \"glutes\", \"equipement_principal\": \"sled machine\", \"body_parts_json\": \"[\\\"upper legs\\\"]\", \"target_muscles_json\": \"[\\\"glutes\\\"]\", \"secondary_muscles_json\": \"[\\\"quadriceps\\\", \\\"hamstrings\\\", \\\"calves\\\"]\", \"equipments_json\": \"[\\\"sled machine\\\"]\", \"instructions_json\": \"[\\\"Step:1 Adjust the seat of the sled machine so that your knees are at a 90-degree angle when your feet are on the footplate.\\\", \\\"Step:2 Sit on the sled machine with your back flat against the backrest and your feet shoulder-width apart on the footplate.\\\", \\\"Step:3 Grip the handles on the sides of the seat for stability.\\\", \\\"Step:4 Push against the footplate to extend your legs, straightening them completely.\\\", \\\"Step:5 Pause for a moment at the top, then slowly bend your knees to lower the footplate back to the starting position.\\\", \\\"Step:6 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(3, 2, 'exercise', '3eGE2JC', '{\"exerciseId\": \"3eGE2JC\", \"name\": \"dumbbell front raise\", \"gifUrl\": \"3eGE2JC.gif\", \"targetMuscles\": [\"delts\"], \"bodyParts\": [\"shoulders\"], \"equipments\": [\"dumbbell\"], \"secondaryMuscles\": [\"biceps\", \"trapezius\"], \"instructions\": [\"Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.\", \"Step:2 Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.\", \"Step:3 Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.\", \"Step:4 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"3eGE2JC\", \"nom\": \"dumbbell front raise\", \"gif_180_path\": \"gifs_180x180/3eGE2JC.gif\", \"gif_360_path\": \"gifs_360x360/3eGE2JC.gif\", \"gif_720_path\": \"gifs_720x720/3eGE2JC.gif\", \"gif_1080_path\": \"gifs_1080x1080/3eGE2JC.gif\", \"body_part_principale\": \"shoulders\", \"muscle_cible_principal\": \"delts\", \"equipement_principal\": \"dumbbell\", \"body_parts_json\": \"[\\\"shoulders\\\"]\", \"target_muscles_json\": \"[\\\"delts\\\"]\", \"secondary_muscles_json\": \"[\\\"biceps\\\", \\\"trapezius\\\"]\", \"equipments_json\": \"[\\\"dumbbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.\\\", \\\"Step:2 Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.\\\", \\\"Step:3 Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.\\\", \\\"Step:4 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(4, 2, 'exercise', '3tAXPQ6', '{\"exerciseId\": \"3tAXPQ6\", \"name\": \"dumbbell over bench revers wrist curl\", \"gifUrl\": \"3tAXPQ6.gif\", \"targetMuscles\": [\"forearms\"], \"bodyParts\": [\"lower arms\"], \"equipments\": [\"dumbbell\"], \"secondaryMuscles\": [\"biceps\", \"brachialis\"], \"instructions\": [\"Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing down.\", \"Step:2 Rest your forearms on the bench, allowing your wrists to hang off the edge.\", \"Step:3 Slowly curl your wrists upward, bringing the dumbbells towards your body.\", \"Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.\", \"Step:5 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"3tAXPQ6\", \"nom\": \"dumbbell over bench revers wrist curl\", \"gif_180_path\": \"gifs_180x180/3tAXPQ6.gif\", \"gif_360_path\": \"gifs_360x360/3tAXPQ6.gif\", \"gif_720_path\": \"gifs_720x720/3tAXPQ6.gif\", \"gif_1080_path\": \"gifs_1080x1080/3tAXPQ6.gif\", \"body_part_principale\": \"lower arms\", \"muscle_cible_principal\": \"forearms\", \"equipement_principal\": \"dumbbell\", \"body_parts_json\": \"[\\\"lower arms\\\"]\", \"target_muscles_json\": \"[\\\"forearms\\\"]\", \"secondary_muscles_json\": \"[\\\"biceps\\\", \\\"brachialis\\\"]\", \"equipments_json\": \"[\\\"dumbbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing down.\\\", \\\"Step:2 Rest your forearms on the bench, allowing your wrists to hang off the edge.\\\", \\\"Step:3 Slowly curl your wrists upward, bringing the dumbbells towards your body.\\\", \\\"Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.\\\", \\\"Step:5 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(5, 2, 'exercise', '3TZduzM', '{\"exerciseId\": \"3TZduzM\", \"name\": \"barbell incline bench press\", \"gifUrl\": \"3TZduzM.gif\", \"targetMuscles\": [\"pectorals\"], \"bodyParts\": [\"chest\"], \"equipments\": [\"barbell\"], \"secondaryMuscles\": [\"shoulders\", \"triceps\"], \"instructions\": [\"Step:1 Set up an incline bench at a 45-degree angle.\", \"Step:2 Lie down on the bench with your feet flat on the ground.\", \"Step:3 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.\", \"Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle.\", \"Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"3TZduzM\", \"nom\": \"barbell incline bench press\", \"gif_180_path\": \"gifs_180x180/3TZduzM.gif\", \"gif_360_path\": \"gifs_360x360/3TZduzM.gif\", \"gif_720_path\": \"gifs_720x720/3TZduzM.gif\", \"gif_1080_path\": \"gifs_1080x1080/3TZduzM.gif\", \"body_part_principale\": \"chest\", \"muscle_cible_principal\": \"pectorals\", \"equipement_principal\": \"barbell\", \"body_parts_json\": \"[\\\"chest\\\"]\", \"target_muscles_json\": \"[\\\"pectorals\\\"]\", \"secondary_muscles_json\": \"[\\\"shoulders\\\", \\\"triceps\\\"]\", \"equipments_json\": \"[\\\"barbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Set up an incline bench at a 45-degree angle.\\\", \\\"Step:2 Lie down on the bench with your feet flat on the ground.\\\", \\\"Step:3 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.\\\", \\\"Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle.\\\", \\\"Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position.\\\", \\\"Step:6 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(6, 2, 'exercise', '3XFdb1Z', '{\"exerciseId\": \"3XFdb1Z\", \"name\": \"cable squatting curl\", \"gifUrl\": \"3XFdb1Z.gif\", \"targetMuscles\": [\"biceps\"], \"bodyParts\": [\"upper arms\"], \"equipments\": [\"cable\"], \"secondaryMuscles\": [\"forearms\"], \"instructions\": [\"Step:1 Attach a cable handle to the lowest setting on a cable machine.\", \"Step:2 Stand facing the machine with your feet shoulder-width apart.\", \"Step:3 Hold the cable handle with an underhand grip, palms facing up, and arms fully extended.\", \"Step:4 Lower your body into a squat position, keeping your back straight and knees behind your toes.\", \"Step:5 As you squat down, curl the cable handle towards your shoulders, keeping your elbows close to your sides.\", \"Step:6 Pause for a moment at the top of the curl, squeezing your biceps.\", \"Step:7 Slowly lower the cable handle back to the starting position, fully extending your arms.\", \"Step:8 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"3XFdb1Z\", \"nom\": \"cable squatting curl\", \"gif_180_path\": \"gifs_180x180/3XFdb1Z.gif\", \"gif_360_path\": \"gifs_360x360/3XFdb1Z.gif\", \"gif_720_path\": \"gifs_720x720/3XFdb1Z.gif\", \"gif_1080_path\": \"gifs_1080x1080/3XFdb1Z.gif\", \"body_part_principale\": \"upper arms\", \"muscle_cible_principal\": \"biceps\", \"equipement_principal\": \"cable\", \"body_parts_json\": \"[\\\"upper arms\\\"]\", \"target_muscles_json\": \"[\\\"biceps\\\"]\", \"secondary_muscles_json\": \"[\\\"forearms\\\"]\", \"equipments_json\": \"[\\\"cable\\\"]\", \"instructions_json\": \"[\\\"Step:1 Attach a cable handle to the lowest setting on a cable machine.\\\", \\\"Step:2 Stand facing the machine with your feet shoulder-width apart.\\\", \\\"Step:3 Hold the cable handle with an underhand grip, palms facing up, and arms fully extended.\\\", \\\"Step:4 Lower your body into a squat position, keeping your back straight and knees behind your toes.\\\", \\\"Step:5 As you squat down, curl the cable handle towards your shoulders, keeping your elbows close to your sides.\\\", \\\"Step:6 Pause for a moment at the top of the curl, squeezing your biceps.\\\", \\\"Step:7 Slowly lower the cable handle back to the starting position, fully extending your arms.\\\", \\\"Step:8 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(7, 2, 'exercise', '4dF3maG', '{\"exerciseId\": \"4dF3maG\", \"name\": \"dumbbell one arm hammer preacher curl\", \"gifUrl\": \"4dF3maG.gif\", \"targetMuscles\": [\"biceps\"], \"bodyParts\": [\"upper arms\"], \"equipments\": [\"dumbbell\"], \"secondaryMuscles\": [\"forearms\"], \"instructions\": [\"Step:1 Sit on a preacher bench with a dumbbell in one hand and your upper arm resting on the pad.\", \"Step:2 Hold the dumbbell with a neutral grip (palms facing your body).\", \"Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.\", \"Step:4 Pause for a moment at the top, squeezing your biceps.\", \"Step:5 Inhale and slowly lower the dumbbell back to the starting position.\", \"Step:6 Repeat for the desired number of repetitions, then switch arms.\"]}', '{\"external_id\": \"4dF3maG\", \"nom\": \"dumbbell one arm hammer preacher curl\", \"gif_180_path\": \"gifs_180x180/4dF3maG.gif\", \"gif_360_path\": \"gifs_360x360/4dF3maG.gif\", \"gif_720_path\": \"gifs_720x720/4dF3maG.gif\", \"gif_1080_path\": \"gifs_1080x1080/4dF3maG.gif\", \"body_part_principale\": \"upper arms\", \"muscle_cible_principal\": \"biceps\", \"equipement_principal\": \"dumbbell\", \"body_parts_json\": \"[\\\"upper arms\\\"]\", \"target_muscles_json\": \"[\\\"biceps\\\"]\", \"secondary_muscles_json\": \"[\\\"forearms\\\"]\", \"equipments_json\": \"[\\\"dumbbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Sit on a preacher bench with a dumbbell in one hand and your upper arm resting on the pad.\\\", \\\"Step:2 Hold the dumbbell with a neutral grip (palms facing your body).\\\", \\\"Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.\\\", \\\"Step:4 Pause for a moment at the top, squeezing your biceps.\\\", \\\"Step:5 Inhale and slowly lower the dumbbell back to the starting position.\\\", \\\"Step:6 Repeat for the desired number of repetitions, then switch arms.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(8, 2, 'exercise', '4dUn2iv', '{\"exerciseId\": \"4dUn2iv\", \"name\": \"barbell standing close grip curl\", \"gifUrl\": \"4dUn2iv.gif\", \"targetMuscles\": [\"biceps\"], \"bodyParts\": [\"upper arms\"], \"equipments\": [\"barbell\"], \"secondaryMuscles\": [\"forearms\"], \"instructions\": [\"Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, hands close together.\", \"Step:2 Keep your elbows close to your torso and your upper arms stationary throughout the movement.\", \"Step:3 Exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.\", \"Step:4 Hold the contracted position for a brief pause as you squeeze your biceps.\", \"Step:5 Inhale as you slowly begin to bring the barbell back to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"4dUn2iv\", \"nom\": \"barbell standing close grip curl\", \"gif_180_path\": \"gifs_180x180/4dUn2iv.gif\", \"gif_360_path\": \"gifs_360x360/4dUn2iv.gif\", \"gif_720_path\": \"gifs_720x720/4dUn2iv.gif\", \"gif_1080_path\": \"gifs_1080x1080/4dUn2iv.gif\", \"body_part_principale\": \"upper arms\", \"muscle_cible_principal\": \"biceps\", \"equipement_principal\": \"barbell\", \"body_parts_json\": \"[\\\"upper arms\\\"]\", \"target_muscles_json\": \"[\\\"biceps\\\"]\", \"secondary_muscles_json\": \"[\\\"forearms\\\"]\", \"equipments_json\": \"[\\\"barbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, hands close together.\\\", \\\"Step:2 Keep your elbows close to your torso and your upper arms stationary throughout the movement.\\\", \\\"Step:3 Exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.\\\", \\\"Step:4 Hold the contracted position for a brief pause as you squeeze your biceps.\\\", \\\"Step:5 Inhale as you slowly begin to bring the barbell back to the starting position.\\\", \\\"Step:6 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(9, 2, 'exercise', '5bpPTHv', '{\"exerciseId\": \"5bpPTHv\", \"name\": \"kettlebell pistol squat\", \"gifUrl\": \"5bpPTHv.gif\", \"targetMuscles\": [\"glutes\"], \"bodyParts\": [\"upper legs\"], \"equipments\": [\"kettlebell\"], \"secondaryMuscles\": [\"quadriceps\", \"hamstrings\", \"calves\"], \"instructions\": [\"Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands.\", \"Step:2 Lift your left foot off the ground and extend it forward, keeping it parallel to the ground.\", \"Step:3 Slowly lower your body down into a squat position, keeping your right foot flat on the ground and your left leg extended.\", \"Step:4 Pause for a moment at the bottom of the squat, then push through your right heel to return to the starting position.\", \"Step:5 Repeat for the desired number of repetitions, then switch legs.\"]}', '{\"external_id\": \"5bpPTHv\", \"nom\": \"kettlebell pistol squat\", \"gif_180_path\": \"gifs_180x180/5bpPTHv.gif\", \"gif_360_path\": \"gifs_360x360/5bpPTHv.gif\", \"gif_720_path\": \"gifs_720x720/5bpPTHv.gif\", \"gif_1080_path\": \"gifs_1080x1080/5bpPTHv.gif\", \"body_part_principale\": \"upper legs\", \"muscle_cible_principal\": \"glutes\", \"equipement_principal\": \"kettlebell\", \"body_parts_json\": \"[\\\"upper legs\\\"]\", \"target_muscles_json\": \"[\\\"glutes\\\"]\", \"secondary_muscles_json\": \"[\\\"quadriceps\\\", \\\"hamstrings\\\", \\\"calves\\\"]\", \"equipments_json\": \"[\\\"kettlebell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands.\\\", \\\"Step:2 Lift your left foot off the ground and extend it forward, keeping it parallel to the ground.\\\", \\\"Step:3 Slowly lower your body down into a squat position, keeping your right foot flat on the ground and your left leg extended.\\\", \\\"Step:4 Pause for a moment at the bottom of the squat, then push through your right heel to return to the starting position.\\\", \\\"Step:5 Repeat for the desired number of repetitions, then switch legs.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(10, 2, 'exercise', '05Cf2v8', '{\"exerciseId\": \"05Cf2v8\", \"name\": \"impossible dips\", \"gifUrl\": \"05Cf2v8.gif\", \"targetMuscles\": [\"triceps\"], \"bodyParts\": [\"upper arms\"], \"equipments\": [\"body weight\"], \"secondaryMuscles\": [\"chest\", \"shoulders\"], \"instructions\": [\"Step:1 Position yourself between two parallel bars with your arms fully extended and your body suspended in the air.\", \"Step:2 Bend your knees and cross your ankles.\", \"Step:3 Lower your body by bending your elbows until your upper arms are parallel to the ground.\", \"Step:4 Pause for a moment, then push yourself back up to the starting position by straightening your arms.\", \"Step:5 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"05Cf2v8\", \"nom\": \"impossible dips\", \"gif_180_path\": \"gifs_180x180/05Cf2v8.gif\", \"gif_360_path\": \"gifs_360x360/05Cf2v8.gif\", \"gif_720_path\": \"gifs_720x720/05Cf2v8.gif\", \"gif_1080_path\": \"gifs_1080x1080/05Cf2v8.gif\", \"body_part_principale\": \"upper arms\", \"muscle_cible_principal\": \"triceps\", \"equipement_principal\": \"body weight\", \"body_parts_json\": \"[\\\"upper arms\\\"]\", \"target_muscles_json\": \"[\\\"triceps\\\"]\", \"secondary_muscles_json\": \"[\\\"chest\\\", \\\"shoulders\\\"]\", \"equipments_json\": \"[\\\"body weight\\\"]\", \"instructions_json\": \"[\\\"Step:1 Position yourself between two parallel bars with your arms fully extended and your body suspended in the air.\\\", \\\"Step:2 Bend your knees and cross your ankles.\\\", \\\"Step:3 Lower your body by bending your elbows until your upper arms are parallel to the ground.\\\", \\\"Step:4 Pause for a moment, then push yourself back up to the starting position by straightening your arms.\\\", \\\"Step:5 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(11, 2, 'exercise', '5uFK1xr', '{\"exerciseId\": \"5uFK1xr\", \"name\": \"barbell seated overhead triceps extension\", \"gifUrl\": \"5uFK1xr.gif\", \"targetMuscles\": [\"triceps\"], \"bodyParts\": [\"upper arms\"], \"equipments\": [\"barbell\"], \"secondaryMuscles\": [\"shoulders\"], \"instructions\": [\"Step:1 Sit on a bench with your back straight and feet flat on the ground.\", \"Step:2 Hold a barbell with an overhand grip, hands shoulder-width apart, and raise it overhead.\", \"Step:3 Lower the barbell behind your head by bending your elbows, keeping your upper arms close to your head.\", \"Step:4 Pause for a moment, then extend your arms to raise the barbell back to the starting position.\", \"Step:5 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"5uFK1xr\", \"nom\": \"barbell seated overhead triceps extension\", \"gif_180_path\": \"gifs_180x180/5uFK1xr.gif\", \"gif_360_path\": \"gifs_360x360/5uFK1xr.gif\", \"gif_720_path\": \"gifs_720x720/5uFK1xr.gif\", \"gif_1080_path\": \"gifs_1080x1080/5uFK1xr.gif\", \"body_part_principale\": \"upper arms\", \"muscle_cible_principal\": \"triceps\", \"equipement_principal\": \"barbell\", \"body_parts_json\": \"[\\\"upper arms\\\"]\", \"target_muscles_json\": \"[\\\"triceps\\\"]\", \"secondary_muscles_json\": \"[\\\"shoulders\\\"]\", \"equipments_json\": \"[\\\"barbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Sit on a bench with your back straight and feet flat on the ground.\\\", \\\"Step:2 Hold a barbell with an overhand grip, hands shoulder-width apart, and raise it overhead.\\\", \\\"Step:3 Lower the barbell behind your head by bending your elbows, keeping your upper arms close to your head.\\\", \\\"Step:4 Pause for a moment, then extend your arms to raise the barbell back to the starting position.\\\", \\\"Step:5 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(12, 2, 'exercise', '5v7KYld', '{\"exerciseId\": \"5v7KYld\", \"name\": \"smith incline bench press\", \"gifUrl\": \"5v7KYld.gif\", \"targetMuscles\": [\"pectorals\"], \"bodyParts\": [\"chest\"], \"equipments\": [\"smith machine\"], \"secondaryMuscles\": [\"shoulders\", \"triceps\"], \"instructions\": [\"Step:1 Adjust the bench to a 30-45 degree incline.\", \"Step:2 Sit on the bench with your back flat against the pad and feet firmly on the ground.\", \"Step:3 Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.\", \"Step:4 Unrack the barbell and lower it slowly towards your upper chest, keeping your elbows slightly tucked in.\", \"Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position, fully extending your arms.\", \"Step:6 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"5v7KYld\", \"nom\": \"smith incline bench press\", \"gif_180_path\": \"gifs_180x180/5v7KYld.gif\", \"gif_360_path\": \"gifs_360x360/5v7KYld.gif\", \"gif_720_path\": \"gifs_720x720/5v7KYld.gif\", \"gif_1080_path\": \"gifs_1080x1080/5v7KYld.gif\", \"body_part_principale\": \"chest\", \"muscle_cible_principal\": \"pectorals\", \"equipement_principal\": \"smith machine\", \"body_parts_json\": \"[\\\"chest\\\"]\", \"target_muscles_json\": \"[\\\"pectorals\\\"]\", \"secondary_muscles_json\": \"[\\\"shoulders\\\", \\\"triceps\\\"]\", \"equipments_json\": \"[\\\"smith machine\\\"]\", \"instructions_json\": \"[\\\"Step:1 Adjust the bench to a 30-45 degree incline.\\\", \\\"Step:2 Sit on the bench with your back flat against the pad and feet firmly on the ground.\\\", \\\"Step:3 Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.\\\", \\\"Step:4 Unrack the barbell and lower it slowly towards your upper chest, keeping your elbows slightly tucked in.\\\", \\\"Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position, fully extending your arms.\\\", \\\"Step:6 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(13, 2, 'exercise', '6bOA1Oi', '{\"exerciseId\": \"6bOA1Oi\", \"name\": \"weighted side bend (on stability ball)\", \"gifUrl\": \"6bOA1Oi.gif\", \"targetMuscles\": [\"abs\"], \"bodyParts\": [\"waist\"], \"equipments\": [\"weighted\"], \"secondaryMuscles\": [\"obliques\", \"lower back\"], \"instructions\": [\"Step:1 Sit on a stability ball with your feet shoulder-width apart and flat on the ground.\", \"Step:2 Hold a weight in one hand and place your other hand on your hip.\", \"Step:3 Engage your core and slowly bend sideways towards the weighted side, keeping your back straight.\", \"Step:4 Pause for a moment at the bottom, then slowly return to the starting position.\", \"Step:5 Repeat for the desired number of repetitions, then switch sides.\"]}', '{\"external_id\": \"6bOA1Oi\", \"nom\": \"weighted side bend (on stability ball)\", \"gif_180_path\": \"gifs_180x180/6bOA1Oi.gif\", \"gif_360_path\": \"gifs_360x360/6bOA1Oi.gif\", \"gif_720_path\": \"gifs_720x720/6bOA1Oi.gif\", \"gif_1080_path\": \"gifs_1080x1080/6bOA1Oi.gif\", \"body_part_principale\": \"waist\", \"muscle_cible_principal\": \"abs\", \"equipement_principal\": \"weighted\", \"body_parts_json\": \"[\\\"waist\\\"]\", \"target_muscles_json\": \"[\\\"abs\\\"]\", \"secondary_muscles_json\": \"[\\\"obliques\\\", \\\"lower back\\\"]\", \"equipments_json\": \"[\\\"weighted\\\"]\", \"instructions_json\": \"[\\\"Step:1 Sit on a stability ball with your feet shoulder-width apart and flat on the ground.\\\", \\\"Step:2 Hold a weight in one hand and place your other hand on your hip.\\\", \\\"Step:3 Engage your core and slowly bend sideways towards the weighted side, keeping your back straight.\\\", \\\"Step:4 Pause for a moment at the bottom, then slowly return to the starting position.\\\", \\\"Step:5 Repeat for the desired number of repetitions, then switch sides.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(14, 2, 'exercise', '6cKQC5E', '{\"exerciseId\": \"6cKQC5E\", \"name\": \"dumbbell one arm upright row\", \"gifUrl\": \"6cKQC5E.gif\", \"targetMuscles\": [\"delts\"], \"bodyParts\": [\"shoulders\"], \"equipments\": [\"dumbbell\"], \"secondaryMuscles\": [\"traps\", \"biceps\"], \"instructions\": [\"Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip.\", \"Step:2 Let the dumbbell hang at arm\'s length in front of your thighs, with your palm facing your body.\", \"Step:3 Keeping your back straight and your core engaged, exhale and lift the dumbbell straight up towards your chin, leading with your elbow.\", \"Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position.\", \"Step:5 Repeat for the desired number of repetitions, then switch to the other arm.\"]}', '{\"external_id\": \"6cKQC5E\", \"nom\": \"dumbbell one arm upright row\", \"gif_180_path\": \"gifs_180x180/6cKQC5E.gif\", \"gif_360_path\": \"gifs_360x360/6cKQC5E.gif\", \"gif_720_path\": \"gifs_720x720/6cKQC5E.gif\", \"gif_1080_path\": \"gifs_1080x1080/6cKQC5E.gif\", \"body_part_principale\": \"shoulders\", \"muscle_cible_principal\": \"delts\", \"equipement_principal\": \"dumbbell\", \"body_parts_json\": \"[\\\"shoulders\\\"]\", \"target_muscles_json\": \"[\\\"delts\\\"]\", \"secondary_muscles_json\": \"[\\\"traps\\\", \\\"biceps\\\"]\", \"equipments_json\": \"[\\\"dumbbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip.\\\", \\\"Step:2 Let the dumbbell hang at arm\'s length in front of your thighs, with your palm facing your body.\\\", \\\"Step:3 Keeping your back straight and your core engaged, exhale and lift the dumbbell straight up towards your chin, leading with your elbow.\\\", \\\"Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position.\\\", \\\"Step:5 Repeat for the desired number of repetitions, then switch to the other arm.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(15, 2, 'exercise', '6HiHHe0', '{\"exerciseId\": \"6HiHHe0\", \"name\": \"barbell standing rocking leg calf raise\", \"gifUrl\": \"6HiHHe0.gif\", \"targetMuscles\": [\"calves\"], \"bodyParts\": [\"lower legs\"], \"equipments\": [\"barbell\"], \"secondaryMuscles\": [\"hamstrings\", \"quadriceps\"], \"instructions\": [\"Step:1 Stand with your feet shoulder-width apart and hold a barbell across your upper back.\", \"Step:2 Raise your heels off the ground as high as possible, balancing on the balls of your feet.\", \"Step:3 Slowly lower your heels back down to the starting position.\", \"Step:4 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"6HiHHe0\", \"nom\": \"barbell standing rocking leg calf raise\", \"gif_180_path\": \"gifs_180x180/6HiHHe0.gif\", \"gif_360_path\": \"gifs_360x360/6HiHHe0.gif\", \"gif_720_path\": \"gifs_720x720/6HiHHe0.gif\", \"gif_1080_path\": \"gifs_1080x1080/6HiHHe0.gif\", \"body_part_principale\": \"lower legs\", \"muscle_cible_principal\": \"calves\", \"equipement_principal\": \"barbell\", \"body_parts_json\": \"[\\\"lower legs\\\"]\", \"target_muscles_json\": \"[\\\"calves\\\"]\", \"secondary_muscles_json\": \"[\\\"hamstrings\\\", \\\"quadriceps\\\"]\", \"equipments_json\": \"[\\\"barbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Stand with your feet shoulder-width apart and hold a barbell across your upper back.\\\", \\\"Step:2 Raise your heels off the ground as high as possible, balancing on the balls of your feet.\\\", \\\"Step:3 Slowly lower your heels back down to the starting position.\\\", \\\"Step:4 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(16, 2, 'exercise', '6kSxYnw', '{\"exerciseId\": \"6kSxYnw\", \"name\": \"barbell wrist curl v. 2\", \"gifUrl\": \"6kSxYnw.gif\", \"targetMuscles\": [\"forearms\"], \"bodyParts\": [\"lower arms\"], \"equipments\": [\"barbell\"], \"secondaryMuscles\": [\"biceps\", \"brachialis\"], \"instructions\": [\"Step:1 Sit on a bench with your feet flat on the ground and your knees bent.\", \"Step:2 Hold a barbell with an underhand grip, palms facing up, and your hands shoulder-width apart.\", \"Step:3 Rest your forearms on your thighs, allowing your wrists to hang off the edge.\", \"Step:4 Slowly curl your wrists upward, bringing the barbell towards your forearms.\", \"Step:5 Pause for a moment at the top, then slowly lower the barbell back down to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"6kSxYnw\", \"nom\": \"barbell wrist curl v. 2\", \"gif_180_path\": \"gifs_180x180/6kSxYnw.gif\", \"gif_360_path\": \"gifs_360x360/6kSxYnw.gif\", \"gif_720_path\": \"gifs_720x720/6kSxYnw.gif\", \"gif_1080_path\": \"gifs_1080x1080/6kSxYnw.gif\", \"body_part_principale\": \"lower arms\", \"muscle_cible_principal\": \"forearms\", \"equipement_principal\": \"barbell\", \"body_parts_json\": \"[\\\"lower arms\\\"]\", \"target_muscles_json\": \"[\\\"forearms\\\"]\", \"secondary_muscles_json\": \"[\\\"biceps\\\", \\\"brachialis\\\"]\", \"equipments_json\": \"[\\\"barbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Sit on a bench with your feet flat on the ground and your knees bent.\\\", \\\"Step:2 Hold a barbell with an underhand grip, palms facing up, and your hands shoulder-width apart.\\\", \\\"Step:3 Rest your forearms on your thighs, allowing your wrists to hang off the edge.\\\", \\\"Step:4 Slowly curl your wrists upward, bringing the barbell towards your forearms.\\\", \\\"Step:5 Pause for a moment at the top, then slowly lower the barbell back down to the starting position.\\\", \\\"Step:6 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(17, 2, 'exercise', '6MfS53i', '{\"exerciseId\": \"6MfS53i\", \"name\": \"dumbbell lying single extension\", \"gifUrl\": \"6MfS53i.gif\", \"targetMuscles\": [\"triceps\"], \"bodyParts\": [\"upper arms\"], \"equipments\": [\"dumbbell\"], \"secondaryMuscles\": [\"shoulders\"], \"instructions\": [\"Step:1 Lie flat on a bench with a dumbbell in one hand and your arm fully extended above your chest.\", \"Step:2 Lower the dumbbell in a controlled manner towards your forehead, keeping your upper arm stationary.\", \"Step:3 Pause briefly at the bottom of the movement, then extend your arm back to the starting position.\", \"Step:4 Repeat for the desired number of repetitions, then switch arms.\"]}', '{\"external_id\": \"6MfS53i\", \"nom\": \"dumbbell lying single extension\", \"gif_180_path\": \"gifs_180x180/6MfS53i.gif\", \"gif_360_path\": \"gifs_360x360/6MfS53i.gif\", \"gif_720_path\": \"gifs_720x720/6MfS53i.gif\", \"gif_1080_path\": \"gifs_1080x1080/6MfS53i.gif\", \"body_part_principale\": \"upper arms\", \"muscle_cible_principal\": \"triceps\", \"equipement_principal\": \"dumbbell\", \"body_parts_json\": \"[\\\"upper arms\\\"]\", \"target_muscles_json\": \"[\\\"triceps\\\"]\", \"secondary_muscles_json\": \"[\\\"shoulders\\\"]\", \"equipments_json\": \"[\\\"dumbbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Lie flat on a bench with a dumbbell in one hand and your arm fully extended above your chest.\\\", \\\"Step:2 Lower the dumbbell in a controlled manner towards your forehead, keeping your upper arm stationary.\\\", \\\"Step:3 Pause briefly at the bottom of the movement, then extend your arm back to the starting position.\\\", \\\"Step:4 Repeat for the desired number of repetitions, then switch arms.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(18, 2, 'exercise', '6sMAmNv', '{\"exerciseId\": \"6sMAmNv\", \"name\": \"dumbbell reverse spider curl\", \"gifUrl\": \"6sMAmNv.gif\", \"targetMuscles\": [\"biceps\"], \"bodyParts\": [\"upper arms\"], \"equipments\": [\"dumbbell\"], \"secondaryMuscles\": [\"forearms\"], \"instructions\": [\"Step:1 Stand up straight with a dumbbell in each hand, palms facing your body and arms fully extended.\", \"Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.\", \"Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.\", \"Step:4 Hold the contracted position for a brief pause as you squeeze your biceps.\", \"Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"6sMAmNv\", \"nom\": \"dumbbell reverse spider curl\", \"gif_180_path\": \"gifs_180x180/6sMAmNv.gif\", \"gif_360_path\": \"gifs_360x360/6sMAmNv.gif\", \"gif_720_path\": \"gifs_720x720/6sMAmNv.gif\", \"gif_1080_path\": \"gifs_1080x1080/6sMAmNv.gif\", \"body_part_principale\": \"upper arms\", \"muscle_cible_principal\": \"biceps\", \"equipement_principal\": \"dumbbell\", \"body_parts_json\": \"[\\\"upper arms\\\"]\", \"target_muscles_json\": \"[\\\"biceps\\\"]\", \"secondary_muscles_json\": \"[\\\"forearms\\\"]\", \"equipments_json\": \"[\\\"dumbbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Stand up straight with a dumbbell in each hand, palms facing your body and arms fully extended.\\\", \\\"Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.\\\", \\\"Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.\\\", \\\"Step:4 Hold the contracted position for a brief pause as you squeeze your biceps.\\\", \\\"Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position.\\\", \\\"Step:6 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(19, 2, 'exercise', '6sYyrRX', '{\"exerciseId\": \"6sYyrRX\", \"name\": \"bent knee lying twist (male)\", \"gifUrl\": \"6sYyrRX.gif\", \"targetMuscles\": [\"glutes\"], \"bodyParts\": [\"upper legs\"], \"equipments\": [\"body weight\"], \"secondaryMuscles\": [\"obliques\", \"hip flexors\"], \"instructions\": [\"Step:1 Lie flat on your back with your knees bent and feet flat on the ground.\", \"Step:2 Extend your arms out to the sides, perpendicular to your body.\", \"Step:3 Keeping your knees together, slowly lower them to one side, aiming to touch the ground with your knees.\", \"Step:4 Pause for a moment, then engage your core and slowly lift your knees back to the starting position.\", \"Step:5 Repeat the movement to the other side.\", \"Step:6 Continue alternating sides for the desired number of repetitions.\"]}', '{\"external_id\": \"6sYyrRX\", \"nom\": \"bent knee lying twist (male)\", \"gif_180_path\": \"gifs_180x180/6sYyrRX.gif\", \"gif_360_path\": \"gifs_360x360/6sYyrRX.gif\", \"gif_720_path\": \"gifs_720x720/6sYyrRX.gif\", \"gif_1080_path\": \"gifs_1080x1080/6sYyrRX.gif\", \"body_part_principale\": \"upper legs\", \"muscle_cible_principal\": \"glutes\", \"equipement_principal\": \"body weight\", \"body_parts_json\": \"[\\\"upper legs\\\"]\", \"target_muscles_json\": \"[\\\"glutes\\\"]\", \"secondary_muscles_json\": \"[\\\"obliques\\\", \\\"hip flexors\\\"]\", \"equipments_json\": \"[\\\"body weight\\\"]\", \"instructions_json\": \"[\\\"Step:1 Lie flat on your back with your knees bent and feet flat on the ground.\\\", \\\"Step:2 Extend your arms out to the sides, perpendicular to your body.\\\", \\\"Step:3 Keeping your knees together, slowly lower them to one side, aiming to touch the ground with your knees.\\\", \\\"Step:4 Pause for a moment, then engage your core and slowly lift your knees back to the starting position.\\\", \\\"Step:5 Repeat the movement to the other side.\\\", \\\"Step:6 Continue alternating sides for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(20, 2, 'exercise', '7F1DVzn', '{\"exerciseId\": \"7F1DVzn\", \"name\": \"lever front pulldown\", \"gifUrl\": \"7F1DVzn.gif\", \"targetMuscles\": [\"lats\"], \"bodyParts\": [\"back\"], \"equipments\": [\"leverage machine\"], \"secondaryMuscles\": [\"biceps\", \"rhomboids\", \"rear deltoids\"], \"instructions\": [\"Step:1 Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.\", \"Step:2 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.\", \"Step:3 Sit upright with your chest lifted and your shoulders back, maintaining a slight arch in your lower back.\", \"Step:4 Engage your lats and pull the handles down towards your chest, squeezing your shoulder blades together.\", \"Step:5 Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"7F1DVzn\", \"nom\": \"lever front pulldown\", \"gif_180_path\": \"gifs_180x180/7F1DVzn.gif\", \"gif_360_path\": \"gifs_360x360/7F1DVzn.gif\", \"gif_720_path\": \"gifs_720x720/7F1DVzn.gif\", \"gif_1080_path\": \"gifs_1080x1080/7F1DVzn.gif\", \"body_part_principale\": \"back\", \"muscle_cible_principal\": \"lats\", \"equipement_principal\": \"leverage machine\", \"body_parts_json\": \"[\\\"back\\\"]\", \"target_muscles_json\": \"[\\\"lats\\\"]\", \"secondary_muscles_json\": \"[\\\"biceps\\\", \\\"rhomboids\\\", \\\"rear deltoids\\\"]\", \"equipments_json\": \"[\\\"leverage machine\\\"]\", \"instructions_json\": \"[\\\"Step:1 Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.\\\", \\\"Step:2 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.\\\", \\\"Step:3 Sit upright with your chest lifted and your shoulders back, maintaining a slight arch in your lower back.\\\", \\\"Step:4 Engage your lats and pull the handles down towards your chest, squeezing your shoulder blades together.\\\", \\\"Step:5 Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.\\\", \\\"Step:6 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(21, 2, 'exercise', '7I6LNUG', '{\"exerciseId\": \"7I6LNUG\", \"name\": \"lever seated row\", \"gifUrl\": \"7I6LNUG.gif\", \"targetMuscles\": [\"upper back\"], \"bodyParts\": [\"back\"], \"equipments\": [\"leverage machine\"], \"secondaryMuscles\": [\"biceps\", \"forearms\"], \"instructions\": [\"Step:1 Adjust the seat height and footrests to a comfortable position.\", \"Step:2 Sit on the machine with your chest against the pad and your feet on the footrests.\", \"Step:3 Grasp the handles with an overhand grip, shoulder-width apart.\", \"Step:4 Keep your back straight and your core engaged.\", \"Step:5 Pull the handles towards your body, squeezing your shoulder blades together.\", \"Step:6 Pause for a moment at the peak of the movement.\", \"Step:7 Slowly release the handles and return to the starting position.\", \"Step:8 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"7I6LNUG\", \"nom\": \"lever seated row\", \"gif_180_path\": \"gifs_180x180/7I6LNUG.gif\", \"gif_360_path\": \"gifs_360x360/7I6LNUG.gif\", \"gif_720_path\": \"gifs_720x720/7I6LNUG.gif\", \"gif_1080_path\": \"gifs_1080x1080/7I6LNUG.gif\", \"body_part_principale\": \"back\", \"muscle_cible_principal\": \"upper back\", \"equipement_principal\": \"leverage machine\", \"body_parts_json\": \"[\\\"back\\\"]\", \"target_muscles_json\": \"[\\\"upper back\\\"]\", \"secondary_muscles_json\": \"[\\\"biceps\\\", \\\"forearms\\\"]\", \"equipments_json\": \"[\\\"leverage machine\\\"]\", \"instructions_json\": \"[\\\"Step:1 Adjust the seat height and footrests to a comfortable position.\\\", \\\"Step:2 Sit on the machine with your chest against the pad and your feet on the footrests.\\\", \\\"Step:3 Grasp the handles with an overhand grip, shoulder-width apart.\\\", \\\"Step:4 Keep your back straight and your core engaged.\\\", \\\"Step:5 Pull the handles towards your body, squeezing your shoulder blades together.\\\", \\\"Step:6 Pause for a moment at the peak of the movement.\\\", \\\"Step:7 Slowly release the handles and return to the starting position.\\\", \\\"Step:8 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(22, 2, 'exercise', '7inpWch', '{\"exerciseId\": \"7inpWch\", \"name\": \"dumbbell standing concentration curl\", \"gifUrl\": \"7inpWch.gif\", \"targetMuscles\": [\"biceps\"], \"bodyParts\": [\"upper arms\"], \"equipments\": [\"dumbbell\"], \"secondaryMuscles\": [\"forearms\"], \"instructions\": [\"Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your arm fully extended and palm facing inwards.\", \"Step:2 Place your opposite hand on your thigh for support.\", \"Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.\", \"Step:4 Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.\", \"Step:5 Hold the contracted position for a brief pause as you squeeze your biceps.\", \"Step:6 Inhale and slowly lower the dumbbell back to the starting position.\", \"Step:7 Repeat for the desired number of repetitions, then switch arms.\"]}', '{\"external_id\": \"7inpWch\", \"nom\": \"dumbbell standing concentration curl\", \"gif_180_path\": \"gifs_180x180/7inpWch.gif\", \"gif_360_path\": \"gifs_360x360/7inpWch.gif\", \"gif_720_path\": \"gifs_720x720/7inpWch.gif\", \"gif_1080_path\": \"gifs_1080x1080/7inpWch.gif\", \"body_part_principale\": \"upper arms\", \"muscle_cible_principal\": \"biceps\", \"equipement_principal\": \"dumbbell\", \"body_parts_json\": \"[\\\"upper arms\\\"]\", \"target_muscles_json\": \"[\\\"biceps\\\"]\", \"secondary_muscles_json\": \"[\\\"forearms\\\"]\", \"equipments_json\": \"[\\\"dumbbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your arm fully extended and palm facing inwards.\\\", \\\"Step:2 Place your opposite hand on your thigh for support.\\\", \\\"Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.\\\", \\\"Step:4 Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.\\\", \\\"Step:5 Hold the contracted position for a brief pause as you squeeze your biceps.\\\", \\\"Step:6 Inhale and slowly lower the dumbbell back to the starting position.\\\", \\\"Step:7 Repeat for the desired number of repetitions, then switch arms.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(23, 2, 'exercise', '7saC5zz', '{\"exerciseId\": \"7saC5zz\", \"name\": \"cable decline fly\", \"gifUrl\": \"7saC5zz.gif\", \"targetMuscles\": [\"pectorals\"], \"bodyParts\": [\"chest\"], \"equipments\": [\"cable\"], \"secondaryMuscles\": [\"shoulders\", \"triceps\"], \"instructions\": [\"Step:1 Adjust the cable machine to a decline position.\", \"Step:2 Stand facing away from the machine with your feet shoulder-width apart.\", \"Step:3 Hold the handles with your palms facing forward and your arms extended straight out in front of you.\", \"Step:4 Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.\", \"Step:5 Pause for a moment at the fully extended position, then slowly return to the starting position.\", \"Step:6 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"7saC5zz\", \"nom\": \"cable decline fly\", \"gif_180_path\": \"gifs_180x180/7saC5zz.gif\", \"gif_360_path\": \"gifs_360x360/7saC5zz.gif\", \"gif_720_path\": \"gifs_720x720/7saC5zz.gif\", \"gif_1080_path\": \"gifs_1080x1080/7saC5zz.gif\", \"body_part_principale\": \"chest\", \"muscle_cible_principal\": \"pectorals\", \"equipement_principal\": \"cable\", \"body_parts_json\": \"[\\\"chest\\\"]\", \"target_muscles_json\": \"[\\\"pectorals\\\"]\", \"secondary_muscles_json\": \"[\\\"shoulders\\\", \\\"triceps\\\"]\", \"equipments_json\": \"[\\\"cable\\\"]\", \"instructions_json\": \"[\\\"Step:1 Adjust the cable machine to a decline position.\\\", \\\"Step:2 Stand facing away from the machine with your feet shoulder-width apart.\\\", \\\"Step:3 Hold the handles with your palms facing forward and your arms extended straight out in front of you.\\\", \\\"Step:4 Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.\\\", \\\"Step:5 Pause for a moment at the fully extended position, then slowly return to the starting position.\\\", \\\"Step:6 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(24, 2, 'exercise', '7zdxRTl', '{\"exerciseId\": \"7zdxRTl\", \"name\": \"smith leg press\", \"gifUrl\": \"7zdxRTl.gif\", \"targetMuscles\": [\"glutes\"], \"bodyParts\": [\"upper legs\"], \"equipments\": [\"smith machine\"], \"secondaryMuscles\": [\"quadriceps\", \"hamstrings\", \"calves\"], \"instructions\": [\"Step:1 Adjust the seat and footplate of the smith machine to a comfortable position.\", \"Step:2 Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate.\", \"Step:3 Grasp the handles or sides of the machine for stability.\", \"Step:4 Push the footplate away from you by extending your legs, keeping your back against the backrest.\", \"Step:5 Pause for a moment at the fully extended position.\", \"Step:6 Slowly bend your knees and lower the footplate back towards you, returning to the starting position.\", \"Step:7 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"7zdxRTl\", \"nom\": \"smith leg press\", \"gif_180_path\": \"gifs_180x180/7zdxRTl.gif\", \"gif_360_path\": \"gifs_360x360/7zdxRTl.gif\", \"gif_720_path\": \"gifs_720x720/7zdxRTl.gif\", \"gif_1080_path\": \"gifs_1080x1080/7zdxRTl.gif\", \"body_part_principale\": \"upper legs\", \"muscle_cible_principal\": \"glutes\", \"equipement_principal\": \"smith machine\", \"body_parts_json\": \"[\\\"upper legs\\\"]\", \"target_muscles_json\": \"[\\\"glutes\\\"]\", \"secondary_muscles_json\": \"[\\\"quadriceps\\\", \\\"hamstrings\\\", \\\"calves\\\"]\", \"equipments_json\": \"[\\\"smith machine\\\"]\", \"instructions_json\": \"[\\\"Step:1 Adjust the seat and footplate of the smith machine to a comfortable position.\\\", \\\"Step:2 Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate.\\\", \\\"Step:3 Grasp the handles or sides of the machine for stability.\\\", \\\"Step:4 Push the footplate away from you by extending your legs, keeping your back against the backrest.\\\", \\\"Step:5 Pause for a moment at the fully extended position.\\\", \\\"Step:6 Slowly bend your knees and lower the footplate back towards you, returning to the starting position.\\\", \\\"Step:7 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47');
INSERT INTO `stg_import` (`stg_id`, `lot_id`, `entite`, `ref_externe`, `source_payload_json`, `payload_normalise_json`, `est_parseable`, `statut_validation`, `code_rejet_potentiel`, `cree_le`) VALUES
(25, 2, 'exercise', '8eqjhOl', '{\"exerciseId\": \"8eqjhOl\", \"name\": \"dumbbell palms in incline bench press\", \"gifUrl\": \"8eqjhOl.gif\", \"targetMuscles\": [\"triceps\"], \"bodyParts\": [\"upper arms\"], \"equipments\": [\"dumbbell\"], \"secondaryMuscles\": [\"chest\", \"shoulders\"], \"instructions\": [\"Step:1 Set up an incline bench at a 45-degree angle.\", \"Step:2 Sit on the bench with your back against the backrest and feet flat on the ground.\", \"Step:3 Hold a dumbbell in each hand with an overhand grip, palms facing inwards.\", \"Step:4 Extend your arms straight up above your chest, keeping a slight bend in your elbows.\", \"Step:5 Lower the dumbbells slowly towards your shoulders, keeping your elbows close to your body.\", \"Step:6 Pause for a moment at the bottom, then press the dumbbells back up to the starting position.\", \"Step:7 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"8eqjhOl\", \"nom\": \"dumbbell palms in incline bench press\", \"gif_180_path\": \"gifs_180x180/8eqjhOl.gif\", \"gif_360_path\": \"gifs_360x360/8eqjhOl.gif\", \"gif_720_path\": \"gifs_720x720/8eqjhOl.gif\", \"gif_1080_path\": \"gifs_1080x1080/8eqjhOl.gif\", \"body_part_principale\": \"upper arms\", \"muscle_cible_principal\": \"triceps\", \"equipement_principal\": \"dumbbell\", \"body_parts_json\": \"[\\\"upper arms\\\"]\", \"target_muscles_json\": \"[\\\"triceps\\\"]\", \"secondary_muscles_json\": \"[\\\"chest\\\", \\\"shoulders\\\"]\", \"equipments_json\": \"[\\\"dumbbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Set up an incline bench at a 45-degree angle.\\\", \\\"Step:2 Sit on the bench with your back against the backrest and feet flat on the ground.\\\", \\\"Step:3 Hold a dumbbell in each hand with an overhand grip, palms facing inwards.\\\", \\\"Step:4 Extend your arms straight up above your chest, keeping a slight bend in your elbows.\\\", \\\"Step:5 Lower the dumbbells slowly towards your shoulders, keeping your elbows close to your body.\\\", \\\"Step:6 Pause for a moment at the bottom, then press the dumbbells back up to the starting position.\\\", \\\"Step:7 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(26, 2, 'exercise', '8K0w2yA', '{\"exerciseId\": \"8K0w2yA\", \"name\": \"assisted hanging knee raise with throw down\", \"gifUrl\": \"8K0w2yA.gif\", \"targetMuscles\": [\"abs\"], \"bodyParts\": [\"waist\"], \"equipments\": [\"assisted\"], \"secondaryMuscles\": [\"hip flexors\", \"lower back\"], \"instructions\": [\"Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you.\", \"Step:2 Engage your core and lift your knees towards your chest, keeping your legs together.\", \"Step:3 Once your knees are at chest level, explosively throw your legs down towards the ground, extending them fully.\", \"Step:4 Allow your legs to swing back up and repeat the movement for the desired number of repetitions.\"]}', '{\"external_id\": \"8K0w2yA\", \"nom\": \"assisted hanging knee raise with throw down\", \"gif_180_path\": \"gifs_180x180/8K0w2yA.gif\", \"gif_360_path\": \"gifs_360x360/8K0w2yA.gif\", \"gif_720_path\": \"gifs_720x720/8K0w2yA.gif\", \"gif_1080_path\": \"gifs_1080x1080/8K0w2yA.gif\", \"body_part_principale\": \"waist\", \"muscle_cible_principal\": \"abs\", \"equipement_principal\": \"assisted\", \"body_parts_json\": \"[\\\"waist\\\"]\", \"target_muscles_json\": \"[\\\"abs\\\"]\", \"secondary_muscles_json\": \"[\\\"hip flexors\\\", \\\"lower back\\\"]\", \"equipments_json\": \"[\\\"assisted\\\"]\", \"instructions_json\": \"[\\\"Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you.\\\", \\\"Step:2 Engage your core and lift your knees towards your chest, keeping your legs together.\\\", \\\"Step:3 Once your knees are at chest level, explosively throw your legs down towards the ground, extending them fully.\\\", \\\"Step:4 Allow your legs to swing back up and repeat the movement for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(27, 2, 'exercise', '8oYqOt9', '{\"exerciseId\": \"8oYqOt9\", \"name\": \"cable seated curl\", \"gifUrl\": \"8oYqOt9.gif\", \"targetMuscles\": [\"biceps\"], \"bodyParts\": [\"upper arms\"], \"equipments\": [\"cable\"], \"secondaryMuscles\": [\"forearms\"], \"instructions\": [\"Step:1 Sit on a cable machine with your feet flat on the ground and your back straight.\", \"Step:2 Grasp the cable attachment with an underhand grip, palms facing up, and your arms fully extended.\", \"Step:3 Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders, contracting your biceps.\", \"Step:4 Pause for a moment at the top of the movement, squeezing your biceps.\", \"Step:5 Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.\", \"Step:6 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"8oYqOt9\", \"nom\": \"cable seated curl\", \"gif_180_path\": \"gifs_180x180/8oYqOt9.gif\", \"gif_360_path\": \"gifs_360x360/8oYqOt9.gif\", \"gif_720_path\": \"gifs_720x720/8oYqOt9.gif\", \"gif_1080_path\": \"gifs_1080x1080/8oYqOt9.gif\", \"body_part_principale\": \"upper arms\", \"muscle_cible_principal\": \"biceps\", \"equipement_principal\": \"cable\", \"body_parts_json\": \"[\\\"upper arms\\\"]\", \"target_muscles_json\": \"[\\\"biceps\\\"]\", \"secondary_muscles_json\": \"[\\\"forearms\\\"]\", \"equipments_json\": \"[\\\"cable\\\"]\", \"instructions_json\": \"[\\\"Step:1 Sit on a cable machine with your feet flat on the ground and your back straight.\\\", \\\"Step:2 Grasp the cable attachment with an underhand grip, palms facing up, and your arms fully extended.\\\", \\\"Step:3 Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders, contracting your biceps.\\\", \\\"Step:4 Pause for a moment at the top of the movement, squeezing your biceps.\\\", \\\"Step:5 Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.\\\", \\\"Step:6 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(28, 2, 'exercise', '8ozhUIZ', '{\"exerciseId\": \"8ozhUIZ\", \"name\": \"barbell standing calf raise\", \"gifUrl\": \"8ozhUIZ.gif\", \"targetMuscles\": [\"calves\"], \"bodyParts\": [\"lower legs\"], \"equipments\": [\"barbell\"], \"secondaryMuscles\": [\"hamstrings\", \"glutes\"], \"instructions\": [\"Step:1 Stand with your feet shoulder-width apart and place a barbell across your upper back.\", \"Step:2 Raise your heels off the ground as high as possible, using only your toes.\", \"Step:3 Pause for a moment at the top, then slowly lower your heels back down to the starting position.\", \"Step:4 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"8ozhUIZ\", \"nom\": \"barbell standing calf raise\", \"gif_180_path\": \"gifs_180x180/8ozhUIZ.gif\", \"gif_360_path\": \"gifs_360x360/8ozhUIZ.gif\", \"gif_720_path\": \"gifs_720x720/8ozhUIZ.gif\", \"gif_1080_path\": \"gifs_1080x1080/8ozhUIZ.gif\", \"body_part_principale\": \"lower legs\", \"muscle_cible_principal\": \"calves\", \"equipement_principal\": \"barbell\", \"body_parts_json\": \"[\\\"lower legs\\\"]\", \"target_muscles_json\": \"[\\\"calves\\\"]\", \"secondary_muscles_json\": \"[\\\"hamstrings\\\", \\\"glutes\\\"]\", \"equipments_json\": \"[\\\"barbell\\\"]\", \"instructions_json\": \"[\\\"Step:1 Stand with your feet shoulder-width apart and place a barbell across your upper back.\\\", \\\"Step:2 Raise your heels off the ground as high as possible, using only your toes.\\\", \\\"Step:3 Pause for a moment at the top, then slowly lower your heels back down to the starting position.\\\", \\\"Step:4 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(29, 2, 'exercise', '8urJS9b', '{\"exerciseId\": \"8urJS9b\", \"name\": \"weighted hyperextension (on stability ball)\", \"gifUrl\": \"8urJS9b.gif\", \"targetMuscles\": [\"spine\"], \"bodyParts\": [\"back\"], \"equipments\": [\"weighted\"], \"secondaryMuscles\": [\"glutes\", \"hamstrings\"], \"instructions\": [\"Step:1 Position yourself face down on a stability ball with your hips resting on the ball and your feet against a wall for stability.\", \"Step:2 Place your hands behind your head or cross them over your chest.\", \"Step:3 Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line.\", \"Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position.\", \"Step:5 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"8urJS9b\", \"nom\": \"weighted hyperextension (on stability ball)\", \"gif_180_path\": \"gifs_180x180/8urJS9b.gif\", \"gif_360_path\": \"gifs_360x360/8urJS9b.gif\", \"gif_720_path\": \"gifs_720x720/8urJS9b.gif\", \"gif_1080_path\": \"gifs_1080x1080/8urJS9b.gif\", \"body_part_principale\": \"back\", \"muscle_cible_principal\": \"spine\", \"equipement_principal\": \"weighted\", \"body_parts_json\": \"[\\\"back\\\"]\", \"target_muscles_json\": \"[\\\"spine\\\"]\", \"secondary_muscles_json\": \"[\\\"glutes\\\", \\\"hamstrings\\\"]\", \"equipments_json\": \"[\\\"weighted\\\"]\", \"instructions_json\": \"[\\\"Step:1 Position yourself face down on a stability ball with your hips resting on the ball and your feet against a wall for stability.\\\", \\\"Step:2 Place your hands behind your head or cross them over your chest.\\\", \\\"Step:3 Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line.\\\", \\\"Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position.\\\", \\\"Step:5 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(30, 2, 'exercise', '8xUv4J7', '{\"exerciseId\": \"8xUv4J7\", \"name\": \"cable seated crunch\", \"gifUrl\": \"8xUv4J7.gif\", \"targetMuscles\": [\"abs\"], \"bodyParts\": [\"waist\"], \"equipments\": [\"cable\"], \"secondaryMuscles\": [\"obliques\"], \"instructions\": [\"Step:1 Sit on a cable machine with your feet flat on the ground and your knees bent.\", \"Step:2 Hold the cable handle with both hands and position it behind your head.\", \"Step:3 Engage your abs and slowly curl your upper body forward, bringing your chest towards your knees.\", \"Step:4 Pause for a moment at the top, then slowly return to the starting position.\", \"Step:5 Repeat for the desired number of repetitions.\"]}', '{\"external_id\": \"8xUv4J7\", \"nom\": \"cable seated crunch\", \"gif_180_path\": \"gifs_180x180/8xUv4J7.gif\", \"gif_360_path\": \"gifs_360x360/8xUv4J7.gif\", \"gif_720_path\": \"gifs_720x720/8xUv4J7.gif\", \"gif_1080_path\": \"gifs_1080x1080/8xUv4J7.gif\", \"body_part_principale\": \"waist\", \"muscle_cible_principal\": \"abs\", \"equipement_principal\": \"cable\", \"body_parts_json\": \"[\\\"waist\\\"]\", \"target_muscles_json\": \"[\\\"abs\\\"]\", \"secondary_muscles_json\": \"[\\\"obliques\\\"]\", \"equipments_json\": \"[\\\"cable\\\"]\", \"instructions_json\": \"[\\\"Step:1 Sit on a cable machine with your feet flat on the ground and your knees bent.\\\", \\\"Step:2 Hold the cable handle with both hands and position it behind your head.\\\", \\\"Step:3 Engage your abs and slowly curl your upper body forward, bringing your chest towards your knees.\\\", \\\"Step:4 Pause for a moment at the top, then slowly return to the starting position.\\\", \\\"Step:5 Repeat for the desired number of repetitions.\\\"]\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:47'),
(31, 3, 'gym', 'GYM_MEMBER_000001', '{\"Age\": 56, \"Gender\": \"Male\", \"Weight (kg)\": 88.3, \"Height (m)\": 1.71, \"Max_BPM\": 180, \"Avg_BPM\": 157, \"Resting_BPM\": 60, \"Session_Duration (hours)\": 1.69, \"Calories_Burned\": 1313.0, \"Workout_Type\": \"Yoga\", \"Fat_Percentage\": 12.6, \"Water_Intake (liters)\": 3.5, \"Workout_Frequency (days/week)\": 4, \"Experience_Level\": 3, \"BMI\": 30.2, \"__line_number\": 2}', '{\"age_source\": 56.0, \"genre_source\": \"Homme\", \"poids_kg\": 88.3, \"taille_cm\": 171.0, \"imc\": 30.2, \"taux_masse_grasse\": 12.6, \"bpm_repos\": 60.0, \"bpm_moyen\": 157.0, \"bpm_max\": 180.0, \"eau_l\": 3.5, \"type_entrainement\": \"Yoga\", \"duree_seance_min\": 101, \"calories_brulees_total\": 1313.0, \"frequence_entrainement_j_sem\": 4.0, \"niveau_experience\": \"3\"}', 1, 'VALIDE', NULL, '2026-04-24 17:27:55'),
